import { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";
import { Menu, X, Search, Star, GitCompare } from "lucide-react";
import { CMD_KEY_CHIP } from "@/lib/platform";
import { useFavorites, useCompare } from "@/lib/useFavorites";

export default function Header() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  const location = useLocation();
  const isHome = location.pathname === "/";
  const favorites = useFavorites();
  const compare = useCompare();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 30);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // On non-home pages we always show the solid background
  const solidBg = scrolled || !isHome;

  // Nav links ordered by importance: critical (Listings, Sellers) survive
  // on narrow viewports; secondary (Features, How It Works, Legal) get
  // pushed into the mobile menu past a breakpoint so 'How It Works' never
  // wraps to three lines on a 1280px laptop.
  const links = [
    { label: "Listings", to: "/listings", type: "route", min: "md" },
    { label: "Sellers", to: "/sellers", type: "route", min: "md" },
    { label: "Shops", to: "/shops", type: "route", min: "md" },
    { label: "Features", to: "/#features", type: "hash", min: "xl" },
    { label: "How It Works", to: "/#how", type: "hash", min: "xl" },
    { label: "Legal", to: "/legal", type: "route", min: "xl" },
  ];

  const renderLink = (l, isMobile = false) => {
    const isActive = l.type === "route" && location.pathname === l.to;
    const cls = isMobile
      ? "text-zinc-300 hover:text-emerald-400 transition-colors"
      : `text-sm text-zinc-400 hover:text-white transition-colors relative group ${isActive ? "text-white" : ""}`;
    const testId = isMobile ? `mobile-nav-link-${l.label.toLowerCase().replace(/\s+/g, "-")}` : `nav-link-${l.label.toLowerCase().replace(/\s+/g, "-")}`;
    const onClick = () => setOpen(false);

    return (
      <Link key={l.to} to={l.to} data-testid={testId} onClick={onClick} className={cls}>
        {l.label}
        {!isMobile && <span className={`absolute left-0 -bottom-1 h-px ${isActive ? "w-full" : "w-0"} bg-emerald-400 group-hover:w-full transition-all duration-300`}></span>}
      </Link>
    );
  };

  // Tailwind min-breakpoint classes
  const minCls = { md: "hidden md:flex", xl: "hidden xl:flex" };

  return (
    <header
      data-testid="site-header"
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        solidBg
          ? "backdrop-blur-2xl bg-bg-base/80 border-b border-white/10 shadow-[0_8px_32px_rgba(0,0,0,0.4)]"
          : "bg-transparent"
      }`}
    >
      <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16 flex items-center justify-between h-20 gap-4">
        <Link to="/" data-testid="logo-link" className="flex items-center gap-3 group shrink-0">
          <div className="relative w-9 h-9 grid place-items-center">
            <div className="absolute inset-0 bg-emerald-500/20 blur-md rounded-full group-hover:bg-emerald-500/40 transition-all"></div>
            <div className="relative w-7 h-7 grid grid-cols-2 grid-rows-2 gap-[2px]">
              <div className="bg-emerald-400"></div>
              <div className="bg-amber-400"></div>
              <div className="bg-amber-400"></div>
              <div className="bg-emerald-400"></div>
            </div>
          </div>
          <span className="font-heading font-extrabold tracking-tight text-base whitespace-nowrap">
            CASTIA<span className="text-emerald-400">.</span>MARKET
          </span>
        </Link>

        <nav className="hidden md:flex items-center gap-7 lg:gap-8">
          {links.map((l) => (
            <div key={l.to} className={minCls[l.min]}>
              {renderLink(l, false)}
            </div>
          ))}
        </nav>

        <div className="hidden md:flex items-center gap-2 lg:gap-3 shrink-0">
          <button
            data-testid="header-cmdk-btn"
            onClick={() => {
              window.dispatchEvent(new KeyboardEvent("keydown", { key: "k", metaKey: true }));
            }}
            className="hidden md:inline-flex items-center gap-2 bg-white/[0.04] hover:bg-white/[0.08] border border-white/10 hover:border-white/20 rounded-md pl-3 pr-2.5 py-2 text-xs text-zinc-400 transition-colors w-40 lg:w-56"
            aria-label="Open command palette"
          >
            <Search className="w-3.5 h-3.5 shrink-0" />
            <span className="flex-1 text-left truncate">Search…</span>
            <span className="hidden lg:inline-flex items-center gap-1 shrink-0">
              <span className="kbd">{CMD_KEY_CHIP}</span><span className="kbd">k</span>
            </span>
          </button>
          <Link
            to="/favorites"
            data-testid="header-favorites-btn"
            aria-label={`Favorites (${favorites.count})`}
            className="relative inline-flex items-center justify-center w-10 h-10 rounded-md bg-white/[0.04] hover:bg-white/[0.08] border border-white/10 hover:border-amber-500/40 text-zinc-300 hover:text-amber-400 transition-colors"
          >
            <Star className={`w-4 h-4 ${favorites.count > 0 ? "fill-amber-400 text-amber-400" : ""}`} />
            {favorites.count > 0 && (
              <span data-testid="header-fav-count" className="absolute -top-1.5 -right-1.5 min-w-[18px] h-[18px] px-1 rounded-full bg-amber-500 text-black font-mono text-[10px] font-bold flex items-center justify-center">
                {favorites.count}
              </span>
            )}
          </Link>
          <Link
            to="/compare"
            data-testid="header-compare-btn"
            aria-label={`Compare (${compare.count})`}
            className="relative inline-flex items-center justify-center w-10 h-10 rounded-md bg-white/[0.04] hover:bg-white/[0.08] border border-white/10 hover:border-emerald-500/40 text-zinc-300 hover:text-emerald-400 transition-colors"
          >
            <GitCompare className={`w-4 h-4 ${compare.count > 0 ? "text-emerald-400" : ""}`} />
            {compare.count > 0 && (
              <span data-testid="header-compare-count" className="absolute -top-1.5 -right-1.5 min-w-[18px] h-[18px] px-1 rounded-full bg-emerald-500 text-black font-mono text-[10px] font-bold flex items-center justify-center">
                {compare.count}
              </span>
            )}
          </Link>
        </div>

        <button
          data-testid="mobile-menu-btn"
          onClick={() => setOpen((s) => !s)}
          className="md:hidden text-white p-2"
          aria-label="Toggle menu"
        >
          {open ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {open && (
        <div data-testid="mobile-menu" className="md:hidden border-t border-white/10 bg-bg-base/95 backdrop-blur-xl">
          <div className="px-6 py-6 flex flex-col gap-5">
            {links.map((l) => renderLink(l, true))}
            <div className="flex items-center gap-2 pt-2 border-t border-white/10">
              <Link
                to="/favorites"
                onClick={() => setOpen(false)}
                data-testid="mobile-favorites-link"
                className="flex-1 inline-flex items-center justify-center gap-2 bg-white/[0.04] border border-white/10 text-white font-bold uppercase tracking-[0.18em] text-xs px-4 py-3 rounded-sm"
              >
                <Star className="w-3.5 h-3.5" /> Favorites {favorites.count > 0 ? `(${favorites.count})` : ""}
              </Link>
              <Link
                to="/compare"
                onClick={() => setOpen(false)}
                data-testid="mobile-compare-link"
                className="flex-1 inline-flex items-center justify-center gap-2 bg-white/[0.04] border border-white/10 text-white font-bold uppercase tracking-[0.18em] text-xs px-4 py-3 rounded-sm"
              >
                <GitCompare className="w-3.5 h-3.5" /> Compare {compare.count > 0 ? `(${compare.count})` : ""}
              </Link>
            </div>
          </div>
        </div>
      )}
    </header>
  );
}
